import{_ as t,o as d,c as o,ai as n}from"./chunks/framework.CaiDwmc7.js";const u=JSON.parse('{"title":"Security Hardening","description":"Context isolation settings, Electron Fuses, and IPC channel restrictions.","frontmatter":{"title":"Security Hardening","description":"Context isolation settings, Electron Fuses, and IPC channel restrictions.","outline":[2,3]},"headers":[],"relativePath":"electron/security.md","filePath":"electron/security.md","lastUpdated":1772487797000}'),r={name:"electron/security.md"};function a(c,e,i,s,l,h){return d(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="security-hardening" tabindex="-1">Security Hardening <a class="header-anchor" href="#security-hardening" aria-label="Permalink to “Security Hardening”">​</a></h1><h2 id="context-isolation" tabindex="-1">Context Isolation <a class="header-anchor" href="#context-isolation" aria-label="Permalink to “Context Isolation”">​</a></h2><p>The Electron app enforces strict process isolation:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th><th>Effect</th></tr></thead><tbody><tr><td><code>contextIsolation</code></td><td><code>true</code></td><td>Renderer cannot access Node.js APIs directly</td></tr><tr><td><code>nodeIntegration</code></td><td><code>false</code></td><td>No <code>require()</code> available in renderer</td></tr><tr><td><code>sandbox</code></td><td>default</td><td>Renderer runs in Chromium sandbox</td></tr></tbody></table><p>All communication between renderer and main process goes through the <code>contextBridge</code> preload script.</p><h2 id="electron-fuses" tabindex="-1">Electron Fuses <a class="header-anchor" href="#electron-fuses" aria-label="Permalink to “Electron Fuses”">​</a></h2><p>Compile-time security toggles via <code>@electron/fuses</code>:</p><table tabindex="0"><thead><tr><th>Fuse</th><th>Setting</th><th>Effect</th></tr></thead><tbody><tr><td><code>RunAsNode</code></td><td>Disabled</td><td>Prevents <code>ELECTRON_RUN_AS_NODE</code> env var abuse</td></tr><tr><td><code>EnableCookieEncryption</code></td><td>Enabled</td><td>Encrypts cookies at rest</td></tr><tr><td><code>EnableNodeOptionsEnvironmentVariable</code></td><td>Disabled</td><td>Blocks <code>NODE_OPTIONS</code> injection</td></tr><tr><td><code>EnableNodeCliInspectArguments</code></td><td>Disabled</td><td>Blocks <code>--inspect</code> debugging in production</td></tr><tr><td><code>OnlyLoadAppFromAsar</code></td><td>Enabled</td><td>Only loads code from ASAR bundle (no filesystem bypass)</td></tr></tbody></table><h2 id="ipc-channel-restrictions" tabindex="-1">IPC Channel Restrictions <a class="header-anchor" href="#ipc-channel-restrictions" aria-label="Permalink to “IPC Channel Restrictions”">​</a></h2><p>The preload script only forwards specific, known IPC channels. The renderer cannot send arbitrary messages to the main process — it can only use <code>send</code>, <code>on</code>, and <code>invoke</code> through the <code>electronAPI</code> bridge.</p>',10)])])}const b=t(r,[["render",a]]);export{u as __pageData,b as default};
